const body=$input.first().json.body||$input.first().json;
const data=body.data||body;
const msg=(data.message?.conversation||data.message?.extendedTextMessage?.text||'').toLowerCase();
const rem=data.key?.remoteJid?.replace('@s.whatsapp.net','')||'';
const alarmas=['mucho dolor','dolor intenso','no puedo dormir','se me ha caído','sangrado','mucha inflamación','alergia','reacción','fiebre','accidente','perdí el diente'];
const esAlarma=alarmas.some(a=>msg.includes(a));
return [{ json: { msg, remitente: rem, esAlarma } }];

